1	package routehealth
2	
3	import (
4		"sort"
5		"strings"
6		"sync"
7	
8		"github.com/easel/fizeau/internal/provider/utilization"
9	)
10	
11	// UtilizationKey identifies one provider endpoint/model utilization sample.
12	type UtilizationKey struct {
13		Provider string
14		Endpoint string
15		Model    string
16	}
17	
18	// EndpointLoad is the normalized load signal used by routing.
19	type EndpointLoad struct {
20		LeaseCount           int
21		NormalizedLoad       float64
22		UtilizationFresh     bool
23		UtilizationSaturated bool
24	}
25	
26	// UtilizationStore retains the most recent utilization sample for each
27	// provider endpoint. It is safe for concurrent use.
28	type UtilizationStore struct {
29		mu      sync.RWMutex
30		samples map[UtilizationKey]utilization.EndpointUtilization
31	}
32	
33	// NewUtilizationStore returns an empty utilization store.
34	func NewUtilizationStore() *UtilizationStore {
35		return &UtilizationStore{
36			samples: make(map[UtilizationKey]utilization.EndpointUtilization),
37		}
38	}
39	
40	// NormalizeUtilizationKey trims whitespace from the utilization dimensions.
41	func NormalizeUtilizationKey(provider, endpoint, model string) UtilizationKey {
42		return UtilizationKey{
43			Provider: strings.TrimSpace(provider),
44			Endpoint: strings.TrimSpace(endpoint),
45			Model:    strings.TrimSpace(model),
46		}
47	}
48	
49	// Record stores the latest utilization sample for key.
50	func (s *UtilizationStore) Record(provider, endpoint, model string, sample utilization.EndpointUtilization) {
51		if s == nil {
52			return
53		}
54		key := NormalizeUtilizationKey(provider, endpoint, model)
55		if key.Provider == "" && key.Endpoint == "" && key.Model == "" {
56			return
57		}
58		if sample.Freshness == "" {
59			sample.Freshness = utilization.FreshnessFresh
60		}
61		s.mu.Lock()
62		defer s.mu.Unlock()
63		if s.samples == nil {
64			s.samples = make(map[UtilizationKey]utilization.EndpointUtilization)
65		}
66		s.samples[key] = cloneUtilization(sample)
67	}
68	
69	// Sample returns the most recent utilization sample for provider/endpoint/model.
70	// When the endpoint-specific sample is unavailable, provider-wide samples are
71	// considered as a fallback so callers can still surface coarse utilization
72	// evidence without guessing at private probe internals.
73	func (s *UtilizationStore) Sample(provider, endpoint, model string) (utilization.EndpointUtilization, bool) {
74		if s == nil {
75			return utilization.EndpointUtilization{}, false
76		}
77		keyProvider := strings.TrimSpace(provider)
78		keyEndpoint := strings.TrimSpace(endpoint)
79		keyModel := strings.TrimSpace(model)
80	
81		s.mu.RLock()
82		defer s.mu.RUnlock()
83		if len(s.samples) == 0 {
84			return utilization.EndpointUtilization{}, false
85		}
86		if sample, ok := s.samples[NormalizeUtilizationKey(keyProvider, keyEndpoint, keyModel)]; ok {
87			return cloneUtilization(sample), true
88		}
89		if keyProvider != "" {
90			if sample, ok := s.samples[NormalizeUtilizationKey(keyProvider, "", keyModel)]; ok {
91				return cloneUtilization(sample), true
92			}
93		}
94		return utilization.EndpointUtilization{}, false
95	}
96	
97	// EndpointLoads returns the normalized load per endpoint for provider/model.
98	// Fresh utilization samples are combined with the supplied lease counts;
99	// stale or missing samples fall back to lease counts only.
100	func (s *UtilizationStore) EndpointLoads(provider, model string, leaseCounts map[string]int) map[string]EndpointLoad {
101		if s == nil {
102			return nil
103		}
104		keyProvider := strings.TrimSpace(provider)
105		keyModel := strings.TrimSpace(model)
106	
107		s.mu.RLock()
108		defer s.mu.RUnlock()
109		if len(s.samples) == 0 && len(leaseCounts) == 0 {
110			return nil
111		}
112	
113		keys := make(map[string]struct{})
114		for endpoint := range leaseCounts {
115			keys[endpoint] = struct{}{}
116		}
117		for key := range s.samples {
118			if keyProvider != "" && key.Provider != keyProvider {
119				continue
120			}
121			if keyModel != "" && key.Model != keyModel {
122				continue
123			}
124			if key.Endpoint != "" {
125				keys[key.Endpoint] = struct{}{}
126			}
127		}
128		if len(keys) == 0 {
129			return nil
130		}
131	
132		out := make(map[string]EndpointLoad, len(keys))
133		for endpoint := range keys {
134			leaseCount := leaseCounts[endpoint]
135			load := EndpointLoad{
136				LeaseCount:       leaseCount,
137				NormalizedLoad:   float64(leaseCount),
138				UtilizationFresh: false,
139			}
140			key := NormalizeUtilizationKey(keyProvider, endpoint, keyModel)
141			sample, ok := s.samples[key]
142			if !ok && keyProvider != "" {
143				// Allow provider-wide samples to match when the caller does not
144				// have a fully-qualified endpoint name.
145				sample, ok = s.samples[NormalizeUtilizationKey(keyProvider, "", keyModel)]
146			}
147			if !ok || sample.Freshness != utilization.FreshnessFresh {
148				out[endpoint] = load
149				continue
150			}
151			normalized, saturated := normalizedLoadFromSample(sample)
152			load.NormalizedLoad = float64(leaseCount) + normalized
153			load.UtilizationFresh = true
154			load.UtilizationSaturated = saturated
155			out[endpoint] = load
156		}
157	
158		return out
159	}
160	
161	func normalizedLoadFromSample(sample utilization.EndpointUtilization) (float64, bool) {
162		var active int
163		var queued int
164		if sample.ActiveRequests != nil {
165			active = *sample.ActiveRequests
166		}
167		if sample.QueuedRequests != nil {
168			queued = *sample.QueuedRequests
169		}
170		if sample.MaxConcurrency != nil && *sample.MaxConcurrency > 0 {
171			total := active + queued
172			pressure := float64(total) / float64(*sample.MaxConcurrency)
173			if pressure < 0 {
174				pressure = 0
175			}
176			return pressure, total >= *sample.MaxConcurrency
177		}
178		if sample.CacheUsage != nil {
179			pressure := *sample.CacheUsage
180			if pressure < 0 {
181				pressure = 0
182			}
183			return pressure, pressure >= 1
184		}
185		total := active + queued
186		if total < 0 {
187			total = 0
188		}
189		return float64(total), false
190	}
191	
192	func cloneUtilization(sample utilization.EndpointUtilization) utilization.EndpointUtilization {
193		out := sample
194		if sample.ActiveRequests != nil {
195			out.ActiveRequests = utilization.Int(*sample.ActiveRequests)
196		}
197		if sample.QueuedRequests != nil {
198			out.QueuedRequests = utilization.Int(*sample.QueuedRequests)
199		}
200		if sample.CacheUsage != nil {
201			out.CacheUsage = utilization.Float64(*sample.CacheUsage)
202		}
203		if sample.MaxConcurrency != nil {
204			out.MaxConcurrency = utilization.Int(*sample.MaxConcurrency)
205		}
206		return out
207	}
208	
209	// EndpointLoadList returns a deterministic endpoint ordering for tests.
210	func EndpointLoadList(loads map[string]EndpointLoad) []string {
211		if len(loads) == 0 {
212			return nil
213		}
214		out := make([]string, 0, len(loads))
215		for endpoint := range loads {
