151	// probeOpenAIModels calls GET /v1/models against baseURL and classifies
152	// failures into the three shapes the catalog cache understands:
153	//
154	//   - *openai.ReachabilityError for 5xx / transport failures (endpoint
155	//     unreachable); cache sets an UnreachableCooldown.
156	//   - errDiscoveryUnsupported for 404 / endpoints that don't expose
157	//     /v1/models; cache marks DiscoverySupported=false and callers
158	//     fall back to passthrough model naming.
159	//   - other errors (401/403 auth, unexpected body) are returned as-is;
160	//     the cache records them but doesn't mark the endpoint unreachable.
161	//
162	// The returned IDs are whatever the server returned in its `data[].id`
163	// list, preserving server-provided order.
164	func probeOpenAIModels(ctx context.Context, baseURL, apiKey string) ([]string, error) {
165		ids, err := openaicompat.DiscoverModels(ctx, baseURL, apiKey)
166		if err == nil {
167			return ids, nil
168		}
169		msg := err.Error()
170		// openaicompat.DiscoverModels returns errors prefixed with
171		// "HTTP <code>: <body>" for non-2xx responses.
172		if strings.Contains(msg, "HTTP 404") {
173			return nil, ErrDiscoveryUnsupported()
174		}
175		if isServerError(msg) || isNetworkFailure(err) {
176			return nil, &openai.ReachabilityError{
177				Endpoint:   baseURL,
178				Operation:  "probe_models",
179				StatusCode: extractStatusCode(msg),
180				Cause:      err,
181			}
182		}
183		return nil, err
184	}
185	
186	// isServerError returns true when the error message indicates a 5xx
187	// response from the discovery endpoint.
188	func isServerError(msg string) bool {
189		for _, prefix := range []string{"HTTP 500", "HTTP 501", "HTTP 502", "HTTP 503", "HTTP 504", "HTTP 505"} {
190			if strings.Contains(msg, prefix) {
191				return true
192			}
193		}
194		return false
195	}
196	
197	// isNetworkFailure returns true when err looks like a transport-level
198	// failure (dial, timeout, TLS, connection reset) — the ReachabilityError
199	// classification applies.
200	func isNetworkFailure(err error) bool {
201		if err == nil {
202			return false
203		}
204		msg := err.Error()
205		markers := []string{
206			"connection refused",
207			"connection reset",
208			"no such host",
209			"tls: handshake",
210			"TLS handshake",
211			"i/o timeout",
212			"dial tcp",
213			"broken pipe",
214		}
215		for _, m := range markers {
216			if strings.Contains(msg, m) {
217				return true
218			}
219		}
220		// Explicitly NOT classifying context.DeadlineExceeded as network —
221		// that's the caller's own deadline.
222		return errors.Is(err, errDialishNetworkError)
223	}
224	
225	// extractStatusCode pulls the status code out of the "HTTP NNN:" prefix
226	// used by openaicompat.DiscoverModels. Returns 0 when no code is found.
227	func extractStatusCode(msg string) int {
228		const prefix = "HTTP "
229		idx := strings.Index(msg, prefix)
230		if idx < 0 {
231			return 0
232		}
233		tail := msg[idx+len(prefix):]
234		if len(tail) < 3 {
235			return 0
236		}
237		code := 0
238		for i := 0; i < 3 && i < len(tail); i++ {
239			c := tail[i]
240			if c < '0' || c > '9' {
241				return 0
242			}
243			code = code*10 + int(c-'0')
244		}
245		return code
246	}
247	
248	// errDialishNetworkError is a sentinel for errors.Is tests. Callers may
249	// wrap their own network errors with this to ensure isNetworkFailure
250	// picks them up even when the message doesn't match one of the literal
251	// markers.
252	var errDialishNetworkError = errors.New("agent: network failure")
253

