421		}
422		if keyServerInstance == "" {
423			keyServerInstance = keyEndpoint
424		}
425		sample, ok := s.routeUtilization.Sample(keyProvider, keyServerInstance, model)
426		if !ok && keyEndpoint != "" && keyEndpoint != keyServerInstance {
427			sample, ok = s.routeUtilization.Sample(keyProvider, keyEndpoint, model)
