499	// escalatePolicyLadder walks routing.PolicyEscalationLadder when Resolve
500	// returns a "no eligible candidate" error and the request's policy is in
501	// the ladder. Returns (true, decision, nil) when a higher tier resolves to
502	// an eligible candidate, or (true, nil, *routing.ErrNoLiveProvider) when
503	// the entire remaining ladder is also empty. Returns (false, _, _) when
504	// escalation does not apply (hard pin error, policy not in ladder, etc.).
505	func escalatePolicyLadder(req routing.Request, in routing.Inputs, origErr error, displayPolicy string) (bool, *routing.Decision, error) {
506		if origErr == nil || req.Policy == "" {
507			return false, nil, nil
508		}
509		if !shouldEscalateOnError(origErr) {
510			return false, nil, nil
511		}
512		startIdx := -1
513		for i, p := range routing.PolicyEscalationLadder {
514			if p == req.Policy {
515				startIdx = i
516				break
517			}
518		}
519		if startIdx < 0 {
520			return false, nil, nil
521		}
522		for i := startIdx + 1; i < len(routing.PolicyEscalationLadder); i++ {
523			probe := req
524			probe.Policy = routing.PolicyEscalationLadder[i]
525			dec, err := routing.Resolve(probe, in)
526			if err == nil && dec != nil && dec.Harness != "" {
527				return true, dec, nil
528			}
529		}
530		starting := displayPolicy
531		if starting == "" {
532			starting = req.Policy
533		}
534		return true, nil, &routing.ErrNoLiveProvider{
535			PromptTokens:   req.EstimatedPromptTokens,
536			RequiresTools:  req.RequiresTools,
537			StartingPolicy: starting,
538			MinPower:       req.MinPower,
539			MaxPower:       req.MaxPower,
540			AllowLocal:     req.AllowLocal,
541		}
542	}
543	
544	// shouldEscalateOnError gates ladder escalation to "no eligible candidate"
545	// errors. Hard caller-pin conflicts (ErrHarnessModelIncompatible,
546	// ErrPolicyRequirementUnsatisfied) are surfaced as-is — escalating past an explicit
547	// pin would silently change the caller's intent.
548	func shouldEscalateOnError(err error) bool {
549		var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
550		if errors.As(err, &modelConstraintAmbiguous) {
551			return false
552		}
553		var modelConstraintNoMatch *ErrModelConstraintNoMatch
554		if errors.As(err, &modelConstraintNoMatch) {
555			return false
556		}
557		var modelErr *routing.ErrHarnessModelIncompatible
558		if errors.As(err, &modelErr) {
559			return false
560		}
561		var pinErr *routing.ErrUnsatisfiablePin
562		if errors.As(err, &pinErr) {
563			return false
564		}
565		var policyErr *routing.ErrPolicyRequirementUnsatisfied
566		if errors.As(err, &policyErr) {
567			return false
568		}
569		return true
570	}
571	
572	func publicRoutingError(err error, candidates []RouteCandidate, requestedPolicy ...string) error {
573		displayPolicy := func(policy string) string {
574			if len(requestedPolicy) > 0 && requestedPolicy[0] != "" {
575				return requestedPolicy[0]
576			}
577			return policy
578		}
579		var modelErr *routing.ErrHarnessModelIncompatible
580		if errors.As(err, &modelErr) {
581			return withRouteCandidates(&ErrHarnessModelIncompatible{
582				Harness:         modelErr.Harness,
583				Model:           modelErr.Model,
584				SupportedModels: append([]string(nil), modelErr.SupportedModels...),
585			}, candidates)
586		}
587		var policyErr *routing.ErrPolicyRequirementUnsatisfied
588		if errors.As(err, &policyErr) {
589			return withRouteCandidates(&ErrPolicyRequirementUnsatisfied{
590				Policy:       displayPolicy(policyErr.Policy),
591				Requirement:  policyErr.Requirement,
592				AttemptedPin: policyErr.AttemptedPin,
593				Rejected:     policyErr.Rejected,
594			}, candidates)
595		}
596		var unknownPolicyErr *routing.ErrUnknownPolicy
597		if errors.As(err, &unknownPolicyErr) {
598			return withRouteCandidates(&ErrUnknownPolicy{
599				Policy: displayPolicy(unknownPolicyErr.Policy),
600			}, candidates)
601		}
602		var pinErr *routing.ErrUnsatisfiablePin
603		if errors.As(err, &pinErr) {
604			return withRouteCandidates(&ErrUnsatisfiablePin{
605				Pin:    pinErr.Pin,
606				Reason: pinErr.Reason,
607			}, candidates)
608		}
609		var noLiveErr *routing.ErrNoLiveProvider
610		if errors.As(err, &noLiveErr) {
611			return withRouteCandidates(&ErrNoLiveProvider{
612				PromptTokens:   noLiveErr.PromptTokens,
613				RequiresTools:  noLiveErr.RequiresTools,
614				StartingPolicy: displayPolicy(noLiveErr.StartingPolicy),
615			}, candidates)
616		}
617		var quotaErr *routing.ErrAllProvidersQuotaExhausted
618		if errors.As(err, &quotaErr) {
619			return withRouteCandidates(&NoViableProviderForNow{
620				RetryAfter:         quotaErr.RetryAfter,
621				ExhaustedProviders: append([]string(nil), quotaErr.ExhaustedProviders...),
622			}, candidates)
623		}
624		return withRouteCandidates(err, candidates)
625	}
626	
627	func withRouteCandidates(err error, candidates []RouteCandidate) error {
628		if err == nil || len(candidates) == 0 {
629			return err
630		}
631		return &routeDecisionError{
632			err:        err,
633			candidates: append([]RouteCandidate(nil), candidates...),
634		}
635	}
