637	func (s *service) applyRouteAttemptCooldowns(in *routing.Inputs) {
638		if in == nil {
639			return
640		}
641		ttl := s.routeAttemptTTL()
642		records := s.activeRouteAttempts(time.Now(), ttl)
643		if len(records) == 0 {
644			return
645		}
646		if in.ProviderCooldowns == nil {
647			in.ProviderCooldowns = make(map[string]time.Time)
648		}
649		if in.CooldownDuration <= 0 {
650			in.CooldownDuration = ttl
651		}
652		for _, record := range records {
653			if record.Key.Provider != "" {
654				existing, ok := in.ProviderCooldowns[record.Key.Provider]
655				if !ok || record.RecordedAt.After(existing) {
656					in.ProviderCooldowns[record.Key.Provider] = record.RecordedAt
657				}
658				// FEAT-004 AC-28: route-attempt failures with dial-class errors
659				// (host unreachable, not a stream-level glitch) are dispatchability
660				// failures, not just non-fatal health risk. Promote them to
661				// ProviderUnreachable so the engine hard-gates on the next call
662				// without waiting for the snapshot's background refresh to catch
663				// up. Non-dial failures (5xx mid-stream, 4xx, context canceled)
664				// stay as soft demotion to preserve sticky-lease across single
665				// transient hiccups.
666				if isDispatchabilityFailure(record.Error) {
667					if in.ProviderUnreachable == nil {
668						in.ProviderUnreachable = make(map[string]time.Time)
669					}
670					existing, ok := in.ProviderUnreachable[record.Key.Provider]
671					if !ok || record.RecordedAt.After(existing) {
672						in.ProviderUnreachable[record.Key.Provider] = record.RecordedAt
673					}
674				}
675			}
676			if record.Key.Provider == "" && record.Key.Harness != "" {
677				for i := range in.Harnesses {
678					if in.Harnesses[i].Name == record.Key.Harness {
679						in.Harnesses[i].InCooldown = true
680					}
681				}
682			}
683		}
684	}
