697	// buildRoutingInputs assembles routing.Inputs from the service's registry
698	// and snapshot-derived provider inventory. The public routing engine stays
699	// unchanged; only the source of provider/model candidates changes.
700	func (s *service) buildRoutingInputs(ctx context.Context) routing.Inputs {
701		// FEAT-004 §Snapshot Freshness — synchronous-freshness contract: at route
702		// decision time, refresh stale providers in-line so the engine sees
703		// current reachability. Fresh providers short-circuit on cache. Caps the
704		// per-route cost at ~5s × stale-provider-count (5s = discoveryRefresh
705		// deadline per source) instead of forcing every source to re-probe.
706		inputs, _ := s.buildRoutingInputsWithCatalog(ctx, serviceRoutingCatalog(), modelsnapshot.RefreshIfStale)
707		return inputs
708	}
709	
710	func (s *service) buildRoutingInputsWithCatalog(ctx context.Context, cat *modelcatalog.Catalog, refresh modelsnapshot.RefreshMode) (routing.Inputs, modelsnapshot.ModelSnapshot) {
711		statuses := s.registry.Discover()
712		statusByName := make(map[string]harnesses.HarnessStatus, len(statuses))
713		for _, st := range statuses {
714			statusByName[st.Name] = st
715		}
716		now := time.Now().UTC()
717		var snapshot modelsnapshot.ModelSnapshot
718		if s.opts.ServiceConfig != nil {
719			if cacheRoot, err := serviceSnapshotCacheRoot(); err == nil {
720				snapshot, _ = assembleModelSnapshotFromServiceConfigWithOptions(
721					ctx,
722					s.opts.ServiceConfig,
723					cat,
724					cacheRoot,
725					modelsnapshot.AssembleOptions{Refresh: refresh},
726				)
727			}
728		}
729	
730		var entries []routing.HarnessEntry
731		for _, name := range s.registry.Names() {
732			cfg, ok := s.registry.Get(name)
733			if !ok {
734				continue
735			}
736			st := statusByName[name]
737			entry := routingHarnessEntryFromMetadata(name, cfg, st)
738			if name == "fiz" && s.opts.ServiceConfig == nil {
739				entry.AutoRoutingEligible = false
740			}
741	
742			if qs, ok := subscriptionQuotaForHarness(name, time.Now()); ok {
743				entry.QuotaOK = qs.OK
744				entry.QuotaStale = qs.Present && !qs.Fresh
745				entry.SubscriptionOK = qs.OK
746				entry.QuotaPercentUsed = qs.PercentUsed
747				entry.QuotaTrend = qs.Trend
748				entry.QuotaReason = qs.Reason
749			}
750	
751			// Native "fiz" harness: enumerate snapshot-derived provider rows.
752			if name == "fiz" && s.opts.ServiceConfig != nil {
753				entry.Providers = s.snapshotProviderEntries(ctx, cat, snapshot)
754				// Tool support for the agent harness is per-(provider, model);
755				// the harness-level baseline is whether ANY provider supports
756				// tools. Engine OR-combines harness and provider SupportsTools
757				// so this lets a per-model no_tools catalog flag actually fire
758				// the RequiresTools gate when every provider's resolved model
759				// is no-tools.
760				if len(entry.Providers) > 0 {
761					entry.SupportsTools = anyProviderSupportsTools(entry.Providers)
762				} else {
763					entry.Available = false
764				}
765			}
766			s.applySubscriptionRoutingCost(&entry, cat)
767			entries = append(entries, entry)
768		}
769		successRate, latencyMS := s.routeMetricSignals(now, s.routeAttemptTTL())
770	
771		// FEAT-004 AC-28: known-down endpoints are dispatchability failures.
772		// Surface provider-level dial failures from the snapshot's discovery
773		// sources via ProviderUnreachable so the routing engine hard-gates them
774		// before any dispatch attempt. This is the synchronous-freshness
775		// contract from FEAT-004 §Snapshot Freshness — autorouting reads the
776		// snapshot, the snapshot owns reachability evidence, and stale-but-
777		// failed providers don't get re-dialed until the cooldown TTL expires.
778		healthCooldownTTL := s.routeAttemptTTL()
779		providerUnreachable := providerCooldownsFromSnapshotErrors(snapshot, s.opts.ServiceConfig, now, healthCooldownTTL)
780	
781		return routing.Inputs{
782			Harnesses:                    entries,
783			ProviderSuccessRate:          successRate,
784			ObservedLatencyMS:            latencyMS,
785			ProviderQuotaExhaustedUntil:  s.providerQuotaExhaustedUntil(now),
786			ProviderUnreachable:          providerUnreachable,
787			CooldownDuration:             healthCooldownTTL,
788			Now:                          now,
789			ModelEligibility:             serviceRoutingModelEligibility(entries, cat),
790			ReasoningResolver:            serviceRoutingReasoningResolver(cat),
791			EndpointLoadResolver:         s.routeEndpointLoadsResolver(now),
792			StickyServerInstanceResolver: s.routeStickyServerInstanceResolver(now),
793		}, snapshot
794	}
795	
796	// dispatchabilityFailureSubstrings matches errors that indicate the upstream
797	// host is unreachable or the provider is currently unusable: TCP-level dial
798	// failures, unrouted DNS, and HTTP 5xx gateway statuses (502/503/504/Bad
799	// Gateway). Treated as dispatchability failures per FEAT-004 AC-28. Both
800	// snapshot discovery errors and route-attempt record errors are classified
801	// through this same predicate.
802	//
803	// Excluded on purpose:
804	//   - 429 / rate-limit (different state machine, ProviderQuotaExhaustedUntil)
805	//   - "context canceled" (operator interrupt; not a provider signal)
806	//   - "provider request timeout: wall-clock" (could mean slow but live host)
807	//   - generic 4xx (auth, validation — surfaces via FilterReasonAuth elsewhere)
808	var dispatchabilityFailureSubstrings = []string{
809		"dial tcp",
810		"connection refused",
811		"no route to host",
812		"network is unreachable",
813		"i/o timeout",
814		"no such host",
815		"502 bad gateway",
816		"503 service unavailable",
817		"504 gateway timeout",
818		" 502 ", // bare status code form (e.g. `: 502 Bad Gateway`)
819		" 503 ",
820		" 504 ",
821	}
822	
823	// isSnapshotDialFailure preserved as a back-compat alias for the v0.13.0
824	// snapshot-side caller. Both now share the same broader predicate.
825	func isSnapshotDialFailure(errMsg string) bool { return isDispatchabilityFailure(errMsg) }
826	
827	func isDispatchabilityFailure(errMsg string) bool {
828		if errMsg == "" {
829			return false
830		}
831		lower := strings.ToLower(errMsg)
832		for _, pat := range dispatchabilityFailureSubstrings {
833			if strings.Contains(lower, pat) {
834				return true
835			}
836		}
837		return false
838	}
839	
840	// providerCooldownsFromSnapshotErrors walks snapshot.Sources and returns a map
841	// of providerName → failure-time for any provider whose most recent discovery
842	// attempt failed with a dial-class error within the cooldown window. The map
843	// feeds routing.Inputs.ProviderCooldowns so engine.go can hard-gate the
844	// candidate before any dispatch attempt.
845	//
846	// Source names are produced by endpointSourceName: they start with the
847	// provider name (optionally followed by "-<endpoint>-<hash>" or "-props").
848	// We match by prefix against the configured provider name set so a source
849	// name like "rg-bragi-club-3090-props" correctly maps to provider
850	// "rg-bragi-club-3090".
851	func providerCooldownsFromSnapshotErrors(snapshot modelsnapshot.ModelSnapshot, cfg ServiceConfigSource, now time.Time, ttl time.Duration) map[string]time.Time {
852		if len(snapshot.Sources) == 0 {
853			return nil
854		}
855		providerNames := []string{}
856		if cfg != nil {
857			providerNames = cfg.ProviderNames()
858		}
859		if len(providerNames) == 0 {
860			return nil
861		}
862		// Sort longest first so "rg-bragi-club-3090" wins over a hypothetical
863		// "rg-bragi" prefix when both are configured.
864		sort.SliceStable(providerNames, func(i, j int) bool {
865			return len(providerNames[i]) > len(providerNames[j])
866		})
867	
868		cooldowns := make(map[string]time.Time)
869		for srcName, meta := range snapshot.Sources {
870			if !isSnapshotDialFailure(meta.Error) {
871				continue
872			}
873			// Use LastRefreshedAt when present (when the cache holds the failure
874			// record itself); otherwise treat as "fresh enough" — the discovery
875			// only emits an error when it tried recently.
876			failedAt := meta.LastRefreshedAt
877			if failedAt.IsZero() {
878				failedAt = now
879			}
880			if ttl > 0 && now.Sub(failedAt) >= ttl {
881				continue
882			}
883			for _, name := range providerNames {
884				if name == srcName || strings.HasPrefix(srcName, name+"-") {
885					if existing, ok := cooldowns[name]; !ok || failedAt.After(existing) {
886						cooldowns[name] = failedAt
887					}
888					break
889				}
890			}
891		}
892		if len(cooldowns) == 0 {
893			return nil
894		}
895		return cooldowns
896	}
897	
898	// ServiceConfigSource is the minimal interface providerCooldownsFromSnapshotErrors
899	// needs from the service config. The real service.opts.ServiceConfig satisfies
900	// it, and tests can pass a stub.
901	type ServiceConfigSource interface {
902		ProviderNames() []string
903	}
904	
905	func (s *service) snapshotProviderEntries(ctx context.Context, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot) []routing.ProviderEntry {
906		if s == nil || s.opts.ServiceConfig == nil {
907			return nil
908		}
909		providerNames := s.opts.ServiceConfig.ProviderNames()
910		if len(providerNames) == 0 || len(snapshot.Models) == 0 {
911			return nil
912		}
913		grouped := make(map[snapshotProviderGroupKey][]modelsnapshot.KnownModel)
914		for _, row := range snapshot.Models {
915			harness := strings.TrimSpace(row.Harness)
916			if harness != "" && harness != "fiz" {
917				continue
918			}
919			providerName := strings.TrimSpace(row.Provider)
920			if providerName == "" {
921				continue
922			}
923			if _, ok := s.opts.ServiceConfig.Provider(providerName); !ok {
924				continue
925			}
926			key := snapshotProviderGroupKey{
927				Provider:        providerName,
928				EndpointName:    strings.TrimSpace(row.EndpointName),
929				EndpointBaseURL: strings.TrimSpace(row.EndpointBaseURL),
930				ServerInstance:  strings.TrimSpace(row.ServerInstance),
931			}
932			grouped[key] = append(grouped[key], row)
933		}
934		if len(grouped) == 0 {
935			return nil
936		}
937	
938		groupCountByProvider := make(map[string]int)
939		for key := range grouped {
940			groupCountByProvider[key.Provider]++
941		}
942	
943		keys := make([]snapshotProviderGroupKey, 0, len(grouped))
944		for key := range grouped {
945			keys = append(keys, key)
946		}
947		sort.Slice(keys, func(i, j int) bool {
948			if keys[i].Provider != keys[j].Provider {
949				return keys[i].Provider < keys[j].Provider
950			}
951			if keys[i].EndpointName != keys[j].EndpointName {
952				return keys[i].EndpointName < keys[j].EndpointName
953			}
954			if keys[i].EndpointBaseURL != keys[j].EndpointBaseURL {
955				return keys[i].EndpointBaseURL < keys[j].EndpointBaseURL
956			}
957			return keys[i].ServerInstance < keys[j].ServerInstance
958		})
959	
960		var entries []routing.ProviderEntry
961		for _, key := range keys {
962			pcfg, ok := s.opts.ServiceConfig.Provider(key.Provider)
963			if !ok || pcfg.ConfigError != "" {
964				continue
965			}
966			rows := append([]modelsnapshot.KnownModel(nil), grouped[key]...)
967			sort.Slice(rows, func(i, j int) bool {
968				if rows[i].EndpointName != rows[j].EndpointName {
969					return rows[i].EndpointName < rows[j].EndpointName
970				}
971				if rows[i].EndpointBaseURL != rows[j].EndpointBaseURL {
972					return rows[i].EndpointBaseURL < rows[j].EndpointBaseURL
973				}
974				if rows[i].ServerInstance != rows[j].ServerInstance {
975					return rows[i].ServerInstance < rows[j].ServerInstance
976				}
977				return rows[i].ID < rows[j].ID
978			})
979			discoveredIDs := snapshotModelIDs(rows)
980			if defaultModel := strings.TrimSpace(pcfg.Model); defaultModel != "" {
981				discoveredIDs = appendUniqueModelIDs(discoveredIDs, defaultModel)
982			}
983			ctxWindows, ctxSources := snapshotProviderContextWindows(ctx, pcfg, cat, rows, discoveredIDs)
984			endpointName := snapshotEndpointName(pcfg, key)
985			routeName := key.Provider
986			if groupCountByProvider[key.Provider] > 1 {
987				switch {
988				case endpointName != "":
989					routeName = endpointProviderRef(key.Provider, endpointName)
990				case key.ServerInstance != "":
991					routeName = endpointProviderRef(key.Provider, key.ServerInstance)
992				case key.EndpointBaseURL != "":
993					routeName = endpointProviderRef(key.Provider, key.EndpointBaseURL)
994				}
995			}
996			baseURL := key.EndpointBaseURL
997			if baseURL == "" {
998				baseURL = pcfg.BaseURL
999			}
1000			serverInstance := key.ServerInstance
1001			if serverInstance == "" {
1002				serverInstance = pcfg.ServerInstance
1003			}
1004			serverInstance = serverinstance.Normalize(baseURL, serverInstance)
1005			entry := routing.ProviderEntry{
1006				Name:                      routeName,
1007				BaseURL:                   baseURL,
1008				ServerInstance:            serverInstance,
1009				EndpointName:              endpointName,
1010				EndpointBaseURL:           baseURL,
1011				DefaultModel:              pcfg.Model,
1012				Billing:                   pcfg.Billing,
1013				CostClass:                 providerRoutingCostClass(pcfg.Type),
1014				DiscoveredIDs:             discoveredIDs,
1015				DiscoveryAttempted:        true,
1016				ContextWindows:            ctxWindows,
1017				ContextWindowSources:      ctxSources,
1018				ContextWindow:             pcfg.ContextWindow,
1019				ContextWindowSource:       contextWindowSourceForProviderConfig(pcfg),
1020				SupportsTools:             providerSupportsTools(cat, pcfg.Model, discoveredIDs),
1021				ExcludeFromDefaultRouting: pcfg.IncludeByDefaultSet && !pcfg.IncludeByDefault,
1022			}
1023			s.applyEndpointRoutingCost(&entry, pcfg, cat)
1024			entries = append(entries, entry)
1025		}
1026		return entries
1027	}
