1103	func snapshotProviderContextWindows(ctx context.Context, pcfg ServiceProviderEntry, cat *modelcatalog.Catalog, rows []modelsnapshot.KnownModel, discoveredIDs []string) (map[string]int, map[string]string) {
1104		_ = ctx
1105		out := make(map[string]int)
1106		sources := make(map[string]string)
1107		rowByID := make(map[string]modelsnapshot.KnownModel, len(rows))
1108		for _, row := range rows {
1109			id := strings.TrimSpace(row.ID)
1110			if id == "" {
1111				continue
1112			}
1113			if _, exists := rowByID[id]; !exists {
1114				rowByID[id] = row
1115			}
1116		}
1117		add := func(modelID string, snapshotWindow int) {
1118			modelID = strings.TrimSpace(modelID)
1119			if modelID == "" {
1120				return
1121			}
1122			window, source := snapshotContextWindow(pcfg, cat, modelID, snapshotWindow)
1123			if window <= 0 {
1124				return
1125			}
1126			out[modelID] = window
1127			sources[modelID] = source
1128		}
1129		if defaultModel := strings.TrimSpace(pcfg.Model); defaultModel != "" {
1130			row, ok := rowByID[defaultModel]
1131			if ok {
1132				add(defaultModel, row.ContextWindow)
1133			} else {
1134				add(defaultModel, 0)
1135			}
1136		}
1137		for _, id := range discoveredIDs {
1138			row, ok := rowByID[id]
1139			if ok {
1140				add(id, row.ContextWindow)
1141				continue
1142			}
1143			add(id, 0)
1144		}
1145		if len(out) == 0 {
1146			return nil, nil
1147		}
1148		return out, sources
1149	}
