1167	// at the given instant for the routing engine. Returns nil when no provider
1168	// is currently in quota_exhausted state, which keeps the routing path
1169	// allocation-free in the common case.
1170	func (s *service) providerQuotaExhaustedUntil(now time.Time) map[string]time.Time {
