1177	// startQuotaRecoveryProbeLoop spawns the goroutine that periodically probes
1178	// quota_exhausted providers and either restores them to available or extends
1179	// their retry_after with bounded backoff. The goroutine is tied to
1180	// QuotaRefreshContext (or context.Background()) so server callers can cancel
1181	// it on shutdown.
1182	func (s *service) startQuotaRecoveryProbeLoop() {
1183		if s == nil || s.providerQuota == nil {
1184			return
1185		}
1186		ctx := s.opts.QuotaRefreshContext
1187		if ctx == nil {
1188			ctx = context.Background()
1189		}
1190		probe := s.quotaRecoveryProber()
1191		if probe == nil {
1192			return
1193		}
1194		go runQuotaRecoveryProbeLoop(ctx, s.providerQuota, probe, defaultQuotaRecoveryFallbackInterval, nil, nil)
1195	}
1196	
1197	// quotaRecoveryProber returns the QuotaRecoveryProber used by the recovery
1198	// loop. It looks up the provider entry in ServiceConfig and reuses the same
1199	// probeProviderStatus the HealthCheck endpoint uses; a "connected" status
1200	// counts as recovery, anything else is reported as a probe failure so the
1201	// retry_after gets extended with backoff.
1202	func (s *service) quotaRecoveryProber() QuotaRecoveryProber {
1203		sc := s.opts.ServiceConfig
1204		if sc == nil {
1205			return nil
1206		}
1207		return func(ctx context.Context, name string) error {
1208			entry, ok := sc.Provider(name)
1209			if !ok {
1210				return fmt.Errorf("provider %q not found", name)
1211			}
1212			probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
1213			defer cancel()
1214			probe := probeProviderStatus(probeCtx, entry, time.Now().UTC())
1215			if probe.status == "connected" {
1216				return nil
1217			}
1218			if probe.detail != "" {
1219				return fmt.Errorf("%s", probe.detail)
1220			}
1221			return fmt.Errorf("%s", probe.status)
1222		}
1223	}
