1332	func serviceRoutingModelEligibility(entries []routing.HarnessEntry, cat *modelcatalog.Catalog) func(model string) (routing.ModelEligibility, bool) {
1333		if cat == nil {
1334			return nil
1335		}
1336		eligibility := make(map[string]routing.ModelEligibility)
1337		add := func(modelID string, includeByDefault bool, status string) {
1338			modelID = strings.TrimSpace(modelID)
1339			if modelID == "" {
1340				return
1341			}
1342			view := modeleligibility.Resolve(modelID, includeByDefault, status, cat)
1343			known := routing.ModelEligibility{
1344				Power:        view.Power,
1345				ExactPinOnly: view.ExactPinOnly,
1346				AutoRoutable: view.AutoRoutable,
1347			}
1348			if existing, ok := eligibility[modelID]; ok {
1349				if known.Power > existing.Power {
1350					existing.Power = known.Power
1351				}
1352				existing.ExactPinOnly = existing.ExactPinOnly || known.ExactPinOnly
1353				existing.AutoRoutable = existing.AutoRoutable || known.AutoRoutable
1354				eligibility[modelID] = existing
1355				return
1356			}
1357			eligibility[modelID] = known
1358		}
1359		for _, h := range entries {
1360			status := "available"
1361			if !h.Available {
1362				status = "unreachable"
1363			}
1364			if h.DefaultModel != "" {
1365				add(h.DefaultModel, true, status)
1366			}
1367			for _, modelID := range h.SupportedModels {
1368				add(modelID, true, status)
1369			}
1370			for _, p := range h.Providers {
1371				includeByDefault := !p.ExcludeFromDefaultRouting
1372				add(p.DefaultModel, includeByDefault, status)
1373				for _, modelID := range p.DiscoveredIDs {
1374					add(modelID, includeByDefault, status)
1375				}
1376			}
1377		}
1378		if len(eligibility) == 0 {
1379			return nil
1380		}
1381		return func(model string) (routing.ModelEligibility, bool) {
1382			known, ok := eligibility[strings.TrimSpace(model)]
1383			return known, ok
1384		}
1385	}
