1529				entry.CostSource = routing.CostSourceUserConfig
1530			} else {
1531				entry.CostUSDPer1kTokens = 0
1532				entry.CostSource = routing.CostSourceUnknown
1533			}
1534			return
1535		}
1536		if cost, ok := catalogCostUSDPer1kTokens(cat, entry.DefaultModel); ok {
1537			entry.ActualCashSpend = true
1538			entry.CostUSDPer1kTokens = cost
1539			entry.CostSource = routing.CostSourceCatalog
1540			return
1541		}
