1587		entry, ok := cat.LookupModel(modelID)
1588		if !ok {
1589			resolved := resolveCatalogCostModel(cat, modelID)
1590			if resolved == "" {
1591				return 0, false
1592			}
1593			entry, ok = cat.LookupModel(resolved)
1594			if !ok {
1595				return 0, false
1596			}
1597		}
1598		input := entry.CostInputPerM
1599		if input == 0 {
1600			input = entry.CostInputPerMTok
1601		}
1602		output := entry.CostOutputPerM
1603		if output == 0 {
1604			output = entry.CostOutputPerMTok
1605		}
1606		switch {
1607		case input > 0 && output > 0:
1608			return ((input + output) / 2) / 1000, true
1609		case input > 0:
1610			return input / 1000, true
1611		case output > 0:
1612			return output / 1000, true
1613		default:
1614			return 0, false
1615		}
1616	}
