1688	// resolveExecuteRouteWithEngine is the post-engine variant of resolveExecuteRoute.
1689	// It is invoked by Execute when the request is under-specified
1690	// (no PreResolved, no fully-specified Harness). Returns nil when the request
1691	// is already specific enough that the legacy resolveExecuteRoute path applies.
1692	func (s *service) resolveExecuteRouteWithEngine(req ServiceExecuteRequest) (*RouteDecision, error) {
1693		rr := RouteRequest{
1694			Policy:        req.Policy,
1695			Model:         req.Model,
1696			Provider:      req.Provider,
1697			Harness:       req.Harness,
1698			Reasoning:     req.Reasoning,
1699			Permissions:   req.Permissions,
1700			CachePolicy:   req.CachePolicy,
1701			MinPower:      req.MinPower,
1702			MaxPower:      req.MaxPower,
1703			Role:          req.Role,
1704			CorrelationID: req.CorrelationID,
1705		}
1706		dec, err := s.ResolveRoute(context.Background(), rr)
1707		if err != nil {
1708			if isExplicitPinError(err) {
1709				return nil, err
1710			}
1711			return nil, fmt.Errorf("ResolveRoute: %w", err)
1712		}
