1716	func providerPreferenceForPolicy(cat *modelcatalog.Catalog, policy string) (string, error) {
1717		if policy == "" {
1718			return routing.ProviderPreferenceLocalFirst, nil
1719		}
1720		switch policy {
1721		case "code-medium":
1722			return "", fmt.Errorf("policy %q is deprecated; use --policy default or --min-power/--max-power", policy)
1723		case "code-high":
1724			return "", fmt.Errorf("policy %q is deprecated; use --policy smart or --min-power/--max-power", policy)
1725		}
1726		if cat == nil {
1727			return "", &ErrUnknownPolicy{Policy: policy}
1728		}
1729		if _, _, ok := policyForName(cat, policy); !ok {
1730			return "", &ErrUnknownPolicy{Policy: policy}
1731		}
1732		preference := providerPreferenceForPolicyName(policy)
1733		switch preference {
1734		case routing.ProviderPreferenceLocalOnly, routing.ProviderPreferenceSubscriptionOnly,
1735			routing.ProviderPreferenceLocalFirst, routing.ProviderPreferenceSubscriptionFirst:
1736			return preference, nil
1737		default:
1738			return "", fmt.Errorf("policy %q has unsupported provider preference %q", policy, preference)
1739		}
1740	}
