2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"net"
8		"strings"
9	)
10	
11	// ErrEndpointUnreachable is the sentinel callers match via errors.Is when
12	// distinguishing "this endpoint is down / unreachable" from everything else.
13	// Wrapped by ReachabilityError.
14	var ErrEndpointUnreachable = errors.New("openai: endpoint unreachable")
15	
16	// ReachabilityError describes a failure attributable to the endpoint being
17	// unreachable or returning a server-side 5xx — distinct from request-level
18	// client errors (4xx) or model-specific errors. Callers use errors.Is(err,
19	// ErrEndpointUnreachable) to detect it.
20	type ReachabilityError struct {
21		// Endpoint is the base URL of the provider that failed.
22		Endpoint string
23		// Operation identifies what was being attempted when the failure
24		// occurred. Typical values: "probe_models", "chat_completions".
25		Operation string
26		// StatusCode is the HTTP status code if the failure was HTTP-level;
27		// 0 for non-HTTP failures (dial error, timeout, TLS handshake, etc.).
28		StatusCode int
29		// Cause is the underlying error.
30		Cause error
31	}
32	
33	func (e *ReachabilityError) Error() string {
34		if e == nil {
35			return ""
36		}
37		endpoint := e.Endpoint
38		if endpoint == "" {
39			endpoint = "<unknown>"
40		}
41		op := e.Operation
42		if op == "" {
43			op = "request"
44		}
45		if e.StatusCode > 0 {
46			return fmt.Sprintf("openai: endpoint unreachable (%s %s: HTTP %d): %v", endpoint, op, e.StatusCode, e.Cause)
47		}
48		return fmt.Sprintf("openai: endpoint unreachable (%s %s): %v", endpoint, op, e.Cause)
49	}
50	
51	// Unwrap returns the underlying cause so errors.As / errors.Unwrap traverse
52	// through the reachability wrapper.
53	func (e *ReachabilityError) Unwrap() error { return e.Cause }
54	
55	// Is reports whether target is ErrEndpointUnreachable. This makes
56	// errors.Is(err, openai.ErrEndpointUnreachable) return true for any
57	// *ReachabilityError regardless of the underlying cause.
58	func (e *ReachabilityError) Is(target error) bool {
59		return target == ErrEndpointUnreachable
60	}
61	
62	// newReachabilityError wraps cause as a ReachabilityError. Returns nil
63	// unchanged when cause is nil. Exported via the helper functions below.
64	func newReachabilityError(endpoint, operation string, statusCode int, cause error) *ReachabilityError {
65		if cause == nil {
66			return nil
67		}
68		return &ReachabilityError{
69			Endpoint:   endpoint,
70			Operation:  operation,
71			StatusCode: statusCode,
72			Cause:      cause,
73		}
74	}
75	
76	// ClassifyHTTPStatus returns a ReachabilityError when the status code is
77	// server-side (5xx); nil otherwise. Callers combine with ClassifyNetwork for
78	// the full picture.
79	func ClassifyHTTPStatus(endpoint, operation string, statusCode int, body string) error {
80		if statusCode >= 500 {
81			return newReachabilityError(endpoint, operation, statusCode,
82				fmt.Errorf("HTTP %d: %s", statusCode, strings.TrimSpace(body)))
83		}
84		return nil
85	}
86	
87	// ClassifyNetwork wraps a transport-level error as a ReachabilityError when
88	// it looks like the endpoint was unreachable — connection refused, dial
89	// timeouts, TLS handshake failure, DNS resolution failure, mid-response reset.
90	// Context cancellation and context-deadline-exceeded are NOT wrapped — those
91	// are the caller's own deadline and should bubble as the caller's concern.
92	// Returns nil when cause is nil.
93	func ClassifyNetwork(endpoint, operation string, cause error) error {
94		if cause == nil {
95			return nil
96		}
97		if errors.Is(cause, context.Canceled) || errors.Is(cause, context.DeadlineExceeded) {
98			// Caller's own context; bubble as-is.
99			return cause
100		}
101		var netErr net.Error
102		if errors.As(cause, &netErr) {
103			return newReachabilityError(endpoint, operation, 0, cause)
104		}
105		// String-sniff for the common cases that don't surface a net.Error
106		// interface — e.g. http transport errors wrapping dial failures.
107		msg := cause.Error()
108		markers := []string{
109			"connection refused",
110			"connection reset",
111			"broken pipe",
112			"no such host",
113			"TLS handshake",
114			"tls: handshake",
115			"EOF",
116			"i/o timeout",
117		}
118		for _, m := range markers {
119			if strings.Contains(msg, m) {
120				return newReachabilityError(endpoint, operation, 0, cause)
121			}
122		}
123		return cause
124	}
125	
126	// Model-family error codes observed on /v1/chat/completions 404 responses.
127	// A generic 404 (no body code) is likely a wrong base URL / path and should
128	// NOT failover; a model-not-found 404 is endpoint-says-yes-to-url but
129	// no-to-this-model and SHOULD failover.
130	var modelNotFoundCodes = []string{
131		"model_not_found",
132		"model_not_supported",
133		"invalid_model",
134		"not_found",
135	}
136	
137	// IsModelNotFound returns true when the response body from a 404 on
138	// /v1/chat/completions contains a model-specific error code. Caller decides
139	// whether to failover based on this + the pinned flag.
140	func IsModelNotFound(body string) bool {
141		lowered := strings.ToLower(body)
142		for _, code := range modelNotFoundCodes {
143			if strings.Contains(lowered, code) {
144				return true
145			}
146		}
147		return false
148	}
149	
150	// ShouldFailover returns true iff err warrants trying the next routing
151	// candidate instead of bubbling up. Returns false when:
152	//   - the request is pinned (operator explicitly chose a provider)
153	//   - the error is a caller-level concern (context.Canceled /
154	//     context.DeadlineExceeded)
155	//   - the error is a request-validation error the next endpoint can't fix
156	//     (400 Bad Request, generic 404 likely indicating wrong URL)
157	//
158	// Returns true for:
159	//   - ReachabilityError (5xx, dial failures, TLS, network resets)
160	//   - 401 / 403 auth failures (another endpoint might have valid auth)
161	//   - 404 responses whose body indicates the model specifically isn't
162	//     served (IsModelNotFound)
163	//   - 429 rate-limit / quota errors
164	//
165	// pinned should be req.Provider != "" captured BEFORE the failover loop.
166	func ShouldFailover(err error, pinned bool) bool {
167		if err == nil {
168			return false
169		}
170		if pinned {
171			return false
172		}
173		if errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded) {
174			return false
175		}
176		if errors.Is(err, ErrEndpointUnreachable) {
177			return true
178		}
179		var httpErr *HTTPStatusError
180		if errors.As(err, &httpErr) {
181			switch {
182			case httpErr.StatusCode == 400:
183				return false
184			case httpErr.StatusCode == 401, httpErr.StatusCode == 403:
185				return true
186			case httpErr.StatusCode == 404:
187				return IsModelNotFound(httpErr.Body)
188			case httpErr.StatusCode == 429:
189				return true
190			case httpErr.StatusCode >= 500:
191				return true
192			}
193		}
194		return false
195	}
196	
197	// HTTPStatusError is a typed client-level HTTP error that carries the status
198	// code and response body so ShouldFailover can classify beyond
199	// ReachabilityError (which is only for 5xx / network). Callers that surface
200	// 4xx errors from openai-compatible servers should wrap them as
201	// HTTPStatusError to participate in the failover policy.
202	type HTTPStatusError struct {
