205	func (s *service) primaryQuotaCacheStatus(ctx context.Context, harnessName string, debounce time.Duration) quotaCacheStatus {
206		now := time.Now()
207		switch harnessName {
208		case "claude":
209			qh, ok := s.harnessByName("claude").(harnesses.QuotaHarness)
210			if !ok {
211				return quotaCacheStatus{}
212			}
213			status, err := qh.QuotaStatus(ctx, now)
214			if err != nil {
215				return quotaCacheStatus{}
216			}
217			if status.State == harnesses.QuotaUnavailable {
218				return quotaCacheStatus{needsRefresh: true}
219			}
220			stale := !status.CapturedAt.IsZero() && now.Sub(status.CapturedAt) >= debounce
221			return quotaCacheStatus{
222				needsRefresh: stale,
223				usable:       !stale,
224			}
225		case "codex":
226			cachePath, err := codexharness.CodexQuotaCachePath()
227			if err != nil {
228				return quotaCacheStatus{}
229			}
230			snap, _ := codexharness.ReadCodexQuotaFrom(cachePath)
231			if snap == nil {
232				return quotaCacheStatus{needsRefresh: true}
233			}
234			decision := codexharness.DecideCodexQuotaRouting(snap, now, debounce)
235			return quotaCacheStatus{
236				needsRefresh: !decision.Fresh || !codexQuotaCacheComplete(snap),
237				usable:       decision.Fresh && decision.PreferCodex,
238			}
239		default:
240			return quotaCacheStatus{}
241		}
242	}
