442		for _, endpoint := range endpoints {
443			endpointEntry := entry
444			endpointEntry.BaseURL = endpoint.BaseURL
445			endpointProbe := probeServiceProviderDetailed(ctx, endpointEntry)
446			endpointProbe.endpointName = endpoint.Name
447			endpointProbe.baseURL = endpoint.BaseURL
448			statuses = append(statuses, endpointStatusFromProbe(endpoint.Name, endpoint.BaseURL, endpointProbe, capturedAt))
449			if endpointProbe.status == "connected" {
450				if aggregate.status != "connected" {
451					aggregate.status = "connected"
452					aggregate.caps = append([]string(nil), endpointProbe.caps...)
453					aggregate.detail = ""
454				}
455				aggregate.modelCount += endpointProbe.modelCount
456				continue
457			}
458			if aggregate.status == "connected" {
459				continue
460			}
461			if shouldPreferProviderProbe(endpointProbe, aggregate) {
462				aggregate.status = endpointProbe.status
463				aggregate.detail = endpointProbe.detail
464				aggregate.caps = append([]string(nil), endpointProbe.caps...)
465				aggregate.baseURL = endpointProbe.baseURL
466				aggregate.endpointName = endpointProbe.endpointName
467			}
468		}
469		aggregate.endpointStatuses = statuses
470		return aggregate
471	}
