package routehealth

import (
	"encoding/json"
	"os"
	"sync"
	"time"
)

// ProbeRecord records the most recent aliveness probe result for a provider endpoint.
type ProbeRecord struct {
	Provider         string    `json:"provider"`
	Endpoint         string    `json:"endpoint,omitempty"`
	LastProbeAt      time.Time `json:"last_probe_at"`
	LastProbeSuccess bool      `json:"last_probe_success"`
}

type probeKey struct {
	Provider string
	Endpoint string
}

// ProbeStore records per-provider aliveness probe results. It is safe for concurrent use.
type ProbeStore struct {
	mu      sync.RWMutex
	records map[probeKey]ProbeRecord
}

// NewProbeStore returns an empty probe store.
func NewProbeStore() *ProbeStore {
	return &ProbeStore{records: make(map[probeKey]ProbeRecord)}
}

// RecordProbe records an aliveness probe result for a provider/endpoint pair.
// Empty endpoint matches the provider's primary endpoint.
func (ps *ProbeStore) RecordProbe(provider, endpoint string, success bool, probeAt time.Time) {
	if provider == "" {
		return
	}
	if probeAt.IsZero() {
		probeAt = time.Now()
	}
	probeAt = probeAt.UTC()
	key := probeKey{Provider: provider, Endpoint: endpoint}
	ps.mu.Lock()
	defer ps.mu.Unlock()
	ps.records[key] = ProbeRecord{
		Provider:         provider,
		Endpoint:         endpoint,
		LastProbeAt:      probeAt,
		LastProbeSuccess: success,
	}
}

// LastProbe returns the most recent probe record for a provider/endpoint pair.
func (ps *ProbeStore) LastProbe(provider, endpoint string) (ProbeRecord, bool) {
	if ps == nil {
		return ProbeRecord{}, false
	}
	key := probeKey{Provider: provider, Endpoint: endpoint}
	ps.mu.RLock()
	defer ps.mu.RUnlock()
	r, ok := ps.records[key]
	return r, ok
}

// ProbeNeeded reports whether a provider/endpoint needs a new probe because its
// last probe is older than interval or has never been probed.
func (ps *ProbeStore) ProbeNeeded(provider, endpoint string, now time.Time, interval time.Duration) bool {
	if ps == nil {
		return false
	}
	r, ok := ps.LastProbe(provider, endpoint)
	if !ok {
		return true
	}
	return now.Sub(r.LastProbeAt) >= interval
}

// UnreachableProviders returns a map of provider name → probe time for providers
// whose most recent probe failed within ttl of now. Used to populate
// routing.Inputs.ProbeUnreachable.
func (ps *ProbeStore) UnreachableProviders(now time.Time, ttl time.Duration) map[string]time.Time {
	if ps == nil {
		return nil
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()
	ps.mu.RLock()
	defer ps.mu.RUnlock()
	var out map[string]time.Time
	for _, r := range ps.records {
		if r.LastProbeSuccess {
			continue
		}
		if ttl > 0 && now.Sub(r.LastProbeAt) > ttl {
			continue
		}
		if out == nil {
			out = make(map[string]time.Time)
		}
		existing, ok := out[r.Provider]
		if !ok || r.LastProbeAt.After(existing) {
			out[r.Provider] = r.LastProbeAt
		}
	}
	return out
}

type persistedProbeStore struct {
	Records []ProbeRecord `json:"records"`
}

// Save persists probe records to a JSON file at path.
func (ps *ProbeStore) Save(path string) error {
	if ps == nil || path == "" {
		return nil
	}
	ps.mu.RLock()
	records := make([]ProbeRecord, 0, len(ps.records))
	for _, r := range ps.records {
		records = append(records, r)
	}
	ps.mu.RUnlock()
	data, err := json.MarshalIndent(persistedProbeStore{Records: records}, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o644)
}

// Load reads probe records from a JSON file at path. Non-existent files are silently ignored.
func (ps *ProbeStore) Load(path string) error {
	if ps == nil || path == "" {
		return nil
	}
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	var stored persistedProbeStore
	if err := json.Unmarshal(data, &stored); err != nil {
		return err
	}
	ps.mu.Lock()
	defer ps.mu.Unlock()
	for _, r := range stored.Records {
		if r.Provider == "" {
			continue
		}
		key := probeKey{Provider: r.Provider, Endpoint: r.Endpoint}
		existing, ok := ps.records[key]
		if !ok || r.LastProbeAt.After(existing.LastProbeAt) {
			ps.records[key] = r
		}
	}
	return nil
}

package routehealth

import (
	"path/filepath"
	"testing"
	"time"
)

func TestProbeStore_RecordAndLastProbe(t *testing.T) {
	store := NewProbeStore()
	now := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)

	store.RecordProbe("bragi", "", false, now)
	r, ok := store.LastProbe("bragi", "")
	if !ok {
		t.Fatal("expected probe record for bragi")
	}
	if r.LastProbeSuccess {
		t.Error("expected probe failure for bragi")
	}
	if !r.LastProbeAt.Equal(now) {
		t.Errorf("LastProbeAt = %v, want %v", r.LastProbeAt, now)
	}

	// Record success — overwrites
	store.RecordProbe("bragi", "", true, now.Add(time.Minute))
	r, ok = store.LastProbe("bragi", "")
	if !ok {
		t.Fatal("expected probe record for bragi after success")
	}
	if !r.LastProbeSuccess {
		t.Error("expected probe success for bragi")
	}
}

func TestProbeStore_UnreachableProviders(t *testing.T) {
	store := NewProbeStore()
	now := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)
	ttl := 10 * time.Minute

	store.RecordProbe("bragi", "", false, now)
	store.RecordProbe("grendel", "", false, now.Add(-15*time.Minute)) // expired
	store.RecordProbe("vidar", "", true, now)                         // reachable

	unreachable := store.UnreachableProviders(now.Add(5*time.Minute), ttl)
	if _, ok := unreachable["bragi"]; !ok {
		t.Error("expected bragi to be unreachable")
	}
	if _, ok := unreachable["grendel"]; ok {
		t.Error("expected grendel to be expired (outside TTL)")
	}
	if _, ok := unreachable["vidar"]; ok {
		t.Error("expected vidar to be reachable, not in unreachable map")
	}
}

func TestProbeStore_ProbeNeeded(t *testing.T) {
	store := NewProbeStore()
	now := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)
	interval := 60 * time.Second

	// Never probed → needed
	if !store.ProbeNeeded("bragi", "", now, interval) {
		t.Error("expected probe needed when never probed")
	}

	store.RecordProbe("bragi", "", true, now)

	// Just probed → not needed
	if store.ProbeNeeded("bragi", "", now.Add(30*time.Second), interval) {
		t.Error("expected probe not needed when probed recently")
	}

	// Interval elapsed → needed
	if !store.ProbeNeeded("bragi", "", now.Add(interval), interval) {
		t.Error("expected probe needed when interval elapsed")
	}
}

// TestRouteHealth_PersistsProbeResults asserts that a fresh process can read
// prior probe results within HealthSignalTTL (AC #5).
func TestRouteHealth_PersistsProbeResults(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "probe_health.json")
	now := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)
	ttl := 10 * time.Minute

	// First process: record a failure and save.
	store1 := NewProbeStore()
	store1.RecordProbe("bragi", "", false, now)
	if err := store1.Save(path); err != nil {
		t.Fatalf("Save: %v", err)
	}

	// Second process: load and verify the probe result is present.
	store2 := NewProbeStore()
	if err := store2.Load(path); err != nil {
		t.Fatalf("Load: %v", err)
	}

	unreachable := store2.UnreachableProviders(now.Add(5*time.Minute), ttl)
	if _, ok := unreachable["bragi"]; !ok {
		t.Fatal("expected bragi to be unreachable after loading persisted probe results")
	}

	// Verify probe beyond TTL is not returned.
	expired := store2.UnreachableProviders(now.Add(ttl+time.Second), ttl)
	if _, ok := expired["bragi"]; ok {
		t.Error("expected bragi to be expired beyond TTL")
	}
}

func TestProbeStore_LoadIgnoresMissingFile(t *testing.T) {
	store := NewProbeStore()
	if err := store.Load("/nonexistent/path/probe.json"); err != nil {
		t.Fatalf("Load of missing file returned error: %v", err)
	}
}

func TestProbeStore_NilSafe(t *testing.T) {
	var ps *ProbeStore
	// nil store should not panic
	if _, ok := ps.LastProbe("bragi", ""); ok {
		t.Error("expected no record from nil store")
	}
	unreachable := ps.UnreachableProviders(time.Now(), time.Minute)
	if len(unreachable) != 0 {
		t.Error("expected empty unreachable from nil store")
	}
}

