input.content:
package fizeau

import (
	"context"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/routehealth"
)

const (
	// defaultHealthProbeInterval is the interval between background aliveness
	// probes when ServiceOptions.HealthProbeInterval is zero.
	defaultHealthProbeInterval = 60 * time.Second
	// defaultHealthSignalTTL is the maximum age of a probe result used to
	// populate routing.Inputs.ProbeUnreachable when HealthSignalTTL is zero.
	defaultHealthSignalTTL = 10 * time.Minute
	// startupProbeTotalTimeout bounds the total wall-clock time spent on
	// startup aliveness probes, regardless of provider count.
	startupProbeTotalTimeout = 5 * time.Second
)

// ProviderAlivenessProber reports whether a provider endpoint is reachable.
// Returns true if reachable, false if not. The prober must respect ctx for
// cancellation.
type ProviderAlivenessProber func(ctx context.Context, provider, baseURL string) bool

// alivenessProbeTarget describes one provider endpoint to probe.
type alivenessProbeTarget struct {
	provider string
	baseURL  string
}

func (s *service) healthProbeInterval() time.Duration {
	if s.opts.HealthProbeInterval > 0 {
		return s.opts.HealthProbeInterval
	}
	return defaultHealthProbeInterval
}

func (s *service) healthSignalTTL() time.Duration {
	if s.opts.HealthSignalTTL > 0 {
		return s.opts.HealthSignalTTL
	}
	return defaultHealthSignalTTL
}

// alivenessProbeTargets enumerates the non-cloud provider endpoints that
// should be probed. Only providers whose billing type indicates fixed/local
// billing are included; cloud subscription providers are excluded.
func (s *service) alivenessProbeTargets() []alivenessProbeTarget {
	if s.opts.ServiceConfig == nil {
		return nil
	}
	var targets []alivenessProbeTarget
	seen := make(map[string]struct{})
	for _, name := range s.opts.ServiceConfig.ProviderNames() {
		entry, ok := s.opts.ServiceConfig.Provider(name)
		if !ok || entry.ConfigError != "" {
			continue
		}
		if !providerTypeUsesFixedBilling(entry.Type) {
			continue
		}
		if entry.BaseURL != "" {
			key := name + "|" + entry.BaseURL
			if _, dup := seen[key]; !dup {
				seen[key] = struct{}{}
				targets = append(targets, alivenessProbeTarget{provider: name, baseURL: entry.BaseURL})
			}
		}
		for _, ep := range entry.Endpoints {
			if ep.BaseURL == "" {
				continue
			}
			key := name + "|" + ep.BaseURL
			if _, dup := seen[key]; !dup {
				seen[key] = struct{}{}
				targets = append(targets, alivenessProbeTarget{provider: name, baseURL: ep.BaseURL})
			}
		}
	}
	return targets
}

// startupAlivenessProbe probes all configured non-cloud providers synchronously
// at service startup. The total probe time is bounded by startupProbeTotalTimeout
// regardless of provider count.
func (s *service) startupAlivenessProbe(ctx context.Context) {
	if s.providerProbe == nil {
		return
	}
	targets := s.alivenessProbeTargets()
	if len(targets) == 0 {
		return
	}
	prober := s.opts.AlivenessProber
	if prober == nil {
		prober = tcpAlivenessProber
	}
	runStartupAlivenessProbes(ctx, targets, s.providerProbe, prober, startupProbeTotalTimeout)
}

// runStartupAlivenessProbes probes each target sequentially within totalTimeout.
// It is exported as a standalone function for direct testing.
func runStartupAlivenessProbes(
	ctx context.Context,
	targets []alivenessProbeTarget,
	store *routehealth.ProbeStore,
	prober ProviderAlivenessProber,
	totalTimeout time.Duration,
) {
	if len(targets) == 0 || store == nil || prober == nil {
		return
	}
	probeCtx := ctx
	if totalTimeout > 0 {
		var cancel context.CancelFunc
		probeCtx, cancel = context.WithTimeout(ctx, totalTimeout)
		defer cancel()
	}
	now := time.Now().UTC()
	for _, t := range targets {
		if probeCtx.Err() != nil {
			break
		}
		success := prober(probeCtx, t.provider, t.baseURL)
		store.RecordProbe(t.provider, "", success, now)
	}
}

// startAlivenessProbeLoop spawns the goroutine that periodically re-probes
// configured non-cloud providers. The goroutine is tied to QuotaRefreshContext
// (or context.Background()) so server callers can cancel it on shutdown.
func (s *service) startAlivenessProbeLoop() {
	if s.providerProbe == nil {
		return
	}
	targets := s.alivenessProbeTargets()
	if len(targets) == 0 {
		return
	}
	ctx := s.opts.QuotaRefreshContext
	if ctx == nil {
		ctx = context.Background()
	}
	prober := s.opts.AlivenessProber
	if prober == nil {
		prober = tcpAlivenessProber
	}
	store := s.providerProbe
	interval := s.healthProbeInterval()
	persistPath := s.opts.PersistRouteHealth
	go runAlivenessProbeLoop(ctx, targets, store, prober, interval, nil, nil, persistPath)
}

// runAlivenessProbeLoop periodically re-probes each target whose last probe
// is older than interval. now and sleep are seams for deterministic tests;
// pass nil for production defaults.
func runAlivenessProbeLoop(
	ctx context.Context,
	targets []alivenessProbeTarget,
	store *routehealth.ProbeStore,
	prober ProviderAlivenessProber,
	interval time.Duration,
	now func() time.Time,
	sleep func(ctx context.Context, d time.Duration) bool,
	persistPath string,
) {
	if now == nil {
		now = time.Now
	}
	if sleep == nil {
		sleep = alivenessLoopSleep
	}
	if interval <= 0 {
		interval = defaultHealthProbeInterval
	}
	for {
		t := now().UTC()
		for _, target := range targets {
			if ctx.Err() != nil {
				return
			}
			if !store.ProbeNeeded(target.provider, "", t, interval) {
				continue
			}
			probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
			success := prober(probeCtx, target.provider, target.baseURL)
			cancel()
			store.RecordProbe(target.provider, "", success, t)
		}
		if persistPath != "" {
			_ = store.Save(persistPath)
		}
		if !sleep(ctx, interval) {
			return
		}
	}
}

func alivenessLoopSleep(ctx context.Context, d time.Duration) bool {
	if d <= 0 {
		return ctx.Err() == nil
	}
	timer := time.NewTimer(d)
	defer timer.Stop()
	select {
	case <-ctx.Done():
		return false
	case <-timer.C:
		return true
	}
}

// tcpAlivenessProber tests endpoint reachability via a TCP connect probe.
func tcpAlivenessProber(ctx context.Context, _, baseURL string) bool {
	addr := extractHostPort(baseURL)
	if addr == "" {
		return false
	}
	d := net.Dialer{}
	conn, err := d.DialContext(ctx, "tcp", addr)
	if err != nil {
		return false
	}
	_ = conn.Close()
	return true
}

// extractHostPort extracts host:port from a base URL, adding the scheme's
// default port when none is specified.
func extractHostPort(baseURL string) string {
	baseURL = strings.TrimSpace(baseURL)
	if baseURL == "" {
		return ""
	}
	if !strings.Contains(baseURL, "://") {
		baseURL = "http://" + baseURL
	}
	u, err := url.Parse(baseURL)
	if err != nil {
		return ""
	}
	host := u.Host
	if host == "" {
		return ""
	}
	if !strings.Contains(host, ":") {
		switch u.Scheme {
		case "https":
			host += ":443"
		default:
			host += ":80"
		}
	}
	return host
}

package fizeau

import (
	"context"
	"sync"
	"testing"
	"time"

	"github.com/easel/fizeau/internal/routehealth"
)

// TestServiceStartup_ProbesConfiguredProviders asserts that startupAlivenessProbe
// (called by Service.New) runs one TCP-connect probe per configured non-cloud
// provider within the startup-bounded time (AC #1).
func TestServiceStartup_ProbesConfiguredProviders(t *testing.T) {
	var mu sync.Mutex
	var probed []string

	fakeProber := ProviderAlivenessProber(func(_ context.Context, provider, _ string) bool {
		mu.Lock()
		probed = append(probed, provider)
		mu.Unlock()
		return false
	})

	sc := &fakeServiceConfig{
		names: []string{"bragi", "openrouter"},
		providers: map[string]ServiceProviderEntry{
			"bragi": {
				// llama-server uses fixed (local) billing — should be probed.
				Type:    "llama-server",
				BaseURL: "http://bragi:1234",
			},
			"openrouter": {
				// openrouter uses per-token billing — should NOT be probed.
				Type:    "openrouter",
				BaseURL: "https://openrouter.ai/api/v1",
			},
		},
	}

	svc := newTestService(t, ServiceOptions{
		ServiceConfig:   sc,
		AlivenessProber: fakeProber,
	})
	svc.providerProbe = routehealth.NewProbeStore()

	// startupAlivenessProbe is what Service.New() calls; test it directly.
	svc.startupAlivenessProbe(context.Background())

	mu.Lock()
	defer mu.Unlock()

	if len(probed) != 1 {
		t.Fatalf("expected 1 probe (bragi only, skip cloud openrouter), got %d: %v", len(probed), probed)
	}
	if probed[0] != "bragi" {
		t.Fatalf("expected probe for bragi, got %q", probed[0])
	}

	// Verify the result is recorded in the probe store.
	r, ok := svc.providerProbe.LastProbe("bragi", "")
	if !ok {
		t.Fatal("no probe record for bragi in store")
	}
	if r.LastProbeSuccess {
		t.Error("expected probe failure recorded (prober returned false)")
	}
}

// TestServiceStartup_TotalTimeoutBoundsProbes asserts that the total startup
// probe time is bounded regardless of provider count.
func TestServiceStartup_TotalTimeoutBoundsProbes(t *testing.T) {
	// Three local providers; prober hangs for 100ms each.
	blocked := make(chan struct{})
	var probeCount int
	var mu sync.Mutex
	fakeProber := ProviderAlivenessProber(func(ctx context.Context, provider, _ string) bool {
		mu.Lock()
		probeCount++
		mu.Unlock()
		select {
		case <-ctx.Done():
			return false
		case <-blocked: // never unblocked in this test
			return true
		}
	})

	targets := []alivenessProbeTarget{
		{provider: "a", baseURL: "http://a:1234"},
		{provider: "b", baseURL: "http://b:1234"},
		{provider: "c", baseURL: "http://c:1234"},
	}

	store := routehealth.NewProbeStore()
	start := time.Now()
	runStartupAlivenessProbes(context.Background(), targets, store, fakeProber, 50*time.Millisecond)
	elapsed := time.Since(start)

	if elapsed > 500*time.Millisecond {
		t.Errorf("startup probe took %v, expected < 500ms (bounded by 50ms timeout)", elapsed)
	}
}

// TestProbeLoop_RetriesDeadProvidersOnInterval asserts that a provider marked
// unreachable by probe is re-probed every HealthProbeInterval and recorded back
// to reachable when it comes online (AC #2).
func TestProbeLoop_RetriesDeadProvidersOnInterval(t *testing.T) {
	baseTime := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)
	interval := 60 * time.Second

	var mu sync.Mutex
	probeResults := []bool{false, true} // first call fails, second succeeds
	probeCount := 0

	prober := ProviderAlivenessProber(func(_ context.Context, _ string, _ string) bool {
		mu.Lock()
		defer mu.Unlock()
		idx := probeCount
		probeCount++
		if idx < len(probeResults) {
			return probeResults[idx]
		}
		return true
	})

	store := routehealth.NewProbeStore()
	targets := []alivenessProbeTarget{
		{provider: "bragi", baseURL: "http://bragi:1234"},
	}

	iteration := 0
	nowFn := func() time.Time {
		return baseTime.Add(time.Duration(iteration) * interval)
	}

	loopsDone := 0
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sleepFn := func(_ context.Context, _ time.Duration) bool {
		loopsDone++
		iteration++
		if loopsDone >= 2 {
			cancel()
			return false
		}
		return true
	}

	runAlivenessProbeLoop(ctx, targets, store, prober, interval, nowFn, sleepFn, "")

	mu.Lock()
	gotCount := probeCount
	mu.Unlock()

	if gotCount != 2 {
		t.Fatalf("expected 2 probes (one per loop iteration), got %d", gotCount)
	}

	r, ok := store.LastProbe("bragi", "")
	if !ok {
		t.Fatal("no probe record for bragi after loop")
	}
	if !r.LastProbeSuccess {
		t.Fatal("expected bragi to be reachable after second probe (prober returned true)")
	}
}

// TestProbeLoop_SkipsProvidersWithFreshProbes asserts that providers probed
// recently are not re-probed until the interval elapses.
func TestProbeLoop_SkipsProvidersWithFreshProbes(t *testing.T) {
	baseTime := time.Date(2026, 5, 14, 10, 0, 0, 0, time.UTC)
	interval := 60 * time.Second

	var mu sync.Mutex
	probeCount := 0
	prober := ProviderAlivenessProber(func(_ context.Context, _ string, _ string) bool {
		mu.Lock()
		probeCount++
		mu.Unlock()
		return true
	})

	store := routehealth.NewProbeStore()
	// Pre-record a fresh probe — should skip re-probing in the first iteration.
	store.RecordProbe("bragi", "", true, baseTime.Add(-10*time.Second))

	targets := []alivenessProbeTarget{
		{provider: "bragi", baseURL: "http://bragi:1234"},
	}

	iteration := 0
	nowFn := func() time.Time {
		return baseTime.Add(time.Duration(iteration) * interval)
	}

	loopsDone := 0
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sleepFn := func(_ context.Context, _ time.Duration) bool {
		loopsDone++
		iteration++
		if loopsDone >= 1 {
			cancel()
			return false
		}
		return true
	}

	runAlivenessProbeLoop(ctx, targets, store, prober, interval, nowFn, sleepFn, "")

	mu.Lock()
	gotCount := probeCount
	mu.Unlock()

	// Probe at T=0: elapsed = 10s < 60s → skip. So probeCount should be 0.
	if gotCount != 0 {
		t.Errorf("expected 0 probes (fresh probe within interval), got %d", gotCount)
	}
}

func TestExtractHostPort(t *testing.T) {
	cases := []struct {
		baseURL string
		want    string
	}{
		{"http://bragi:1234", "bragi:1234"},
		{"https://example.com", "example.com:443"},
		{"http://localhost", "localhost:80"},
		{"http://127.0.0.1:11434", "127.0.0.1:11434"},
		{"", ""},
		{"not a url ://", ""},
	}
	for _, tc := range cases {
		got := extractHostPort(tc.baseURL)
		if got != tc.want {
			t.Errorf("extractHostPort(%q) = %q, want %q", tc.baseURL, got, tc.want)
		}
	}
}

