			}
			key := name + "|" + ep.BaseURL
			if _, dup := seen[key]; !dup {
				seen[key] = struct{}{}
				targets = append(targets, alivenessProbeTarget{provider: name, baseURL: ep.BaseURL})
			}
		}
	}
