527		canonicalHarness := req.Harness
528		if canonicalHarness == "local" {
529			canonicalHarness = "fiz"
530		}
531		if err := explicitPinError(req, in); err != nil {
532			return &Decision{}, err
533		}
534	
535		var ranked []rankedCandidate
536		for _, h := range in.Harnesses {
537			// TestOnly harnesses (script/virtual) only reachable via explicit override.
538			if h.TestOnly && canonicalHarness != h.Name {
539				continue
540			}
541			// Automatic profile/tier routing is restricted to harnesses with full
542			// coverage. Explicit Harness pins can still use experimental/ad-hoc
543			// harnesses.
544			if canonicalHarness == "" && !h.AutoRoutingEligible {
545				continue
546			}
547			// Hard harness override: skip non-matching harnesses.
548			if canonicalHarness != "" && canonicalHarness != h.Name {
