563			ranked[i].out.ScoreComponents = scoreComponents(req.Policy, ranked[i].internal)
564			ranked[i].out.Reason = fmt.Sprintf("policy=%s; score=%.1f", req.Policy, ranked[i].out.Score)
565		}
566		neutralCost, hasKnownCost := neutralKnownCost(ranked)
567	
568		// Sort: eligible first, then descending score, then cost, then locality,
569		// then alphabetical.
570		sort.SliceStable(ranked, func(i, j int) bool {
571			ei, ej := ranked[i].out.Eligible, ranked[j].out.Eligible
572			if ei != ej {
573				return ei
574			}
575			if !ei {
